import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Pagination, Slideout, TableCard } from '../../ui';
import JobsListToolbar from './JobsListToolbar';
import { filterBySearchQuery } from './jobsListFilterUtils';
import { jobsService, type ImportRunDetail, type JobDirection, type PlatformEventDetail } from '../../services/jobs';
import { JobEventTypeFilter } from './components/JobEventTypeFilter';
import { JobEventsTable, buildPlatformEventSearchText } from './components/JobEventsTable';
import { JobEventDetailPanel } from './components/JobEventDetailPanel';
import { JobImportRunDetailPanel } from './components/JobImportRunDetailPanel';
import { useAppToast } from '@linm-soft/common-components';
import styles from './JobInternalPage.module.css';

const PAGE_SIZE = 20;
const SLIDEOUT_WIDTH = '640px';

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

const JobEventsPage: React.FC = () => {
  useNavTitle('Danh sách platform events');
  const toast = useAppToast();
  const [searchParams, setSearchParams] = useSearchParams();

  const direction = (searchParams.get('direction') as JobDirection | null) ?? undefined;
  const [eventTypes, setEventTypes] = React.useState<Awaited<ReturnType<typeof jobsService.getEventTypes>>>([]);
  const [eventType, setEventType] = React.useState(searchParams.get('eventType') ?? '');
  const [status, setStatus] = React.useState(searchParams.get('status') ?? '');
  const [page, setPage] = React.useState(Math.max(1, Number(searchParams.get('page') || 1)));
  const [events, setEvents] = React.useState<Awaited<ReturnType<typeof jobsService.getEvents>>['items']>([]);
  const [total, setTotal] = React.useState(0);
  const [loading, setLoading] = React.useState(true);
  const [selectedEventId, setSelectedEventId] = React.useState<string | null>(searchParams.get('eventId'));
  const [eventDetail, setEventDetail] = React.useState<PlatformEventDetail | null>(null);
  const [loadingDetail, setLoadingDetail] = React.useState(false);
  const [retention, setRetention] = React.useState<Awaited<ReturnType<typeof jobsService.getEventRetention>> | null>(null);
  const [cleanupPreview, setCleanupPreview] = React.useState<
    Awaited<ReturnType<typeof jobsService.getEventCleanupPreview>> | null
  >(null);
  const [cleanupRunning, setCleanupRunning] = React.useState(false);
  const [linkedRunId, setLinkedRunId] = React.useState<string | null>(null);
  const [linkedRunDetail, setLinkedRunDetail] = React.useState<ImportRunDetail | null>(null);
  const [loadingLinkedRun, setLoadingLinkedRun] = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');
  const runIdFilter = searchParams.get('runId') ?? '';

  const filteredEvents = React.useMemo(
    () =>
      filterBySearchQuery(events, searchQuery, (e) => buildPlatformEventSearchText(e)),
    [events, searchQuery],
  );

  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));

  const syncUrl = React.useCallback(
    (nextPage: number, nextEventId: string | null, nextRunId?: string) => {
      const sp = new URLSearchParams();
      if (direction) sp.set('direction', direction);
      if (eventType) sp.set('eventType', eventType);
      if (status) sp.set('status', status);
      if (nextPage > 1) sp.set('page', String(nextPage));
      if (nextEventId) sp.set('eventId', nextEventId);
      const rid = nextRunId ?? runIdFilter;
      if (rid) sp.set('runId', rid);
      setSearchParams(sp, { replace: true });
    },
    [direction, eventType, status, runIdFilter, setSearchParams],
  );

  const loadEvents = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getEvents({
        page,
        pageSize: PAGE_SIZE,
        direction,
        eventType: eventType || undefined,
        processingStatus: status || undefined,
        runId: runIdFilter || undefined,
      })
      .then((r) => {
        setEvents(r.items);
        setTotal(r.total);
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [page, direction, eventType, status, runIdFilter, toast]);

  const loadDetail = React.useCallback(
    (eventId: string) => {
      setLoadingDetail(true);
      return jobsService
        .getEvent(eventId)
        .then(setEventDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setEventDetail(null);
        })
        .finally(() => setLoadingDetail(false));
    },
    [toast],
  );

  const loadRetention = React.useCallback(() => {
    Promise.all([jobsService.getEventRetention(), jobsService.getEventCleanupPreview()])
      .then(([cfg, preview]) => {
        setRetention(cfg);
        setCleanupPreview(preview);
      })
      .catch(() => undefined);
  }, []);

  React.useEffect(() => {
    jobsService.getEventTypes(direction).then(setEventTypes).catch(() => undefined);
    loadRetention();
  }, [direction, loadRetention]);

  React.useEffect(() => {
    loadEvents();
  }, [loadEvents]);

  React.useEffect(() => {
    syncUrl(page, selectedEventId);
  }, [page, selectedEventId, syncUrl]);

  const selectedIsProcessing =
    events.find((e) => e.eventId === selectedEventId)?.processingStatus === 'Processing';

  React.useEffect(() => {
    if (!selectedEventId) {
      setEventDetail(null);
      return undefined;
    }
    loadDetail(selectedEventId);
    if (!selectedIsProcessing) return undefined;
    const t = setInterval(() => {
      loadDetail(selectedEventId);
      loadEvents();
    }, 4000);
    return () => clearInterval(t);
  }, [selectedEventId, selectedIsProcessing, loadDetail, loadEvents]);

  const handleSelectEvent = (eventId: string) => {
    setSelectedEventId(eventId);
  };

  const closeEventDetail = () => {
    setSelectedEventId(null);
    setEventDetail(null);
  };

  const openImportRunSlideout = React.useCallback(
    (runId: string) => {
      setLinkedRunId(runId);
      setLoadingLinkedRun(true);
      jobsService
        .getImportRun(runId)
        .then(setLinkedRunDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setLinkedRunDetail(null);
        })
        .finally(() => setLoadingLinkedRun(false));
    },
    [toast],
  );

  const closeLinkedRunSlideout = React.useCallback(() => {
    setLinkedRunId(null);
    setLinkedRunDetail(null);
  }, []);

  const handleCleanup = () => {
    setCleanupRunning(true);
    jobsService
      .runEventCleanup()
      .then((r) => {
        toast.success(`Đã xóa ${r.deletedCount} event (trước ${formatDate(r.cutoffUtc)})`);
        loadRetention();
        loadEvents();
        if (selectedEventId) loadDetail(selectedEventId);
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setCleanupRunning(false));
  };

  return (
    <div data-testid="job-events-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/dashboard">Dashboard</Link>
        {' · '}
        <Link to="/admin/jobs/internal?tab=events">Job nội bộ</Link>
      </p>

      {retention ? (
        <div
          style={{
            marginBottom: 16,
            padding: 12,
            background: '#f8fafc',
            borderRadius: 8,
            fontSize: 13,
            display: 'flex',
            flexWrap: 'wrap',
            gap: 12,
            alignItems: 'center',
          }}
        >
          <span>
            Cleanup tự động: <strong>{retention.enabled ? 'Bật' : 'Tắt'}</strong> — giữ{' '}
            <strong>{retention.retentionDays}</strong> ngày (mỗi {retention.cleanupIntervalHours}h)
          </span>
          {cleanupPreview ? (
            <span style={{ color: '#64748b' }}>
              Đủ điều kiện xóa: <strong>{cleanupPreview.eligibleCount}</strong> (trước{' '}
              {formatDate(cleanupPreview.cutoffUtc)})
            </span>
          ) : null}
          <Button
            type="button"
            variant="secondary"
            disabled={cleanupRunning || !retention.enabled}
            onClick={handleCleanup}
          >
            {cleanupRunning ? 'Đang dọn…' : 'Dọn ngay'}
          </Button>
        </div>
      ) : null}

      <div className={styles.shell}>
        <TableCard
          listShell
          header={
            <div>
              <h4 className={styles.listHeaderTitle}>Platform events ({total})</h4>
              <p className={styles.listHint}>
                Click dòng để xem chi tiết. Tìm theo runId, mã CT, connector hoặc loại event.
                {runIdFilter ? (
                  <>
                    {' '}
                    Đang lọc run{' '}
                    <code style={{ fontSize: 12 }}>{runIdFilter.slice(0, 8)}…</code>
                    {' · '}
                    <Link to={direction ? `/admin/jobs/events?direction=${direction}` : '/admin/jobs/events'}>
                      Bỏ lọc run
                    </Link>
                  </>
                ) : null}
              </p>
              <JobEventTypeFilter
                eventTypes={eventTypes}
                eventType={eventType}
                onEventTypeChange={(v) => {
                  setEventType(v);
                  setPage(1);
                  setSearchQuery('');
                }}
                status={status}
                onStatusChange={(v) => {
                  setStatus(v);
                  setPage(1);
                  setSearchQuery('');
                }}
              />
              <JobsListToolbar
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                searchPlaceholder="Tìm runId, mã CT, connector…"
                searchTestId="job-events-search"
                onRefresh={loadEvents}
                refreshDisabled={loading}
                totalCount={events.length}
                filteredCount={filteredEvents.length}
                loading={loading}
                itemLabel="event"
              />
            </div>
          }
          footer={
            !loading && events.length > 0 ? (
              <Pagination
                currentPage={page}
                totalPages={totalPages}
                totalCount={total}
                pageSize={PAGE_SIZE}
                itemLabel="event"
                onPageChange={setPage}
              />
            ) : undefined
          }
        >
          <div className={styles.eventsTableWrap}>
            {loading && events.length === 0 ? (
              <p className={styles.gridLoading}>Đang tải…</p>
            ) : filteredEvents.length === 0 ? (
              <p className={styles.gridEmpty}>
                {searchQuery.trim() ? 'Không tìm thấy event phù hợp trên trang này.' : 'Không có event'}
              </p>
            ) : (
              <JobEventsTable
                events={filteredEvents}
                selectedEventId={selectedEventId}
                onSelectEvent={handleSelectEvent}
              />
            )}
          </div>
        </TableCard>
      </div>

      <Slideout
        isOpen={Boolean(selectedEventId)}
        onClose={closeEventDetail}
        title="Chi tiết event"
        width={SLIDEOUT_WIDTH}
        data-testid="job-event-detail-slideout"
        customFooter={
          <button type="button" className={styles.closeBtn} onClick={closeEventDetail}>
            Đóng
          </button>
        }
      >
        <div className={styles.slideoutBody}>
          {!selectedEventId ? (
            <p style={{ color: '#64748b' }}>Chọn một dòng để xem chi tiết.</p>
          ) : loadingDetail && !eventDetail ? (
            <p>Đang tải…</p>
          ) : eventDetail ? (
            <JobEventDetailPanel detail={eventDetail} onOpenImportRun={openImportRunSlideout} />
          ) : (
            <p style={{ color: '#64748b' }}>Không tải được chi tiết.</p>
          )}
        </div>
      </Slideout>

      <Slideout
        isOpen={Boolean(linkedRunId)}
        onClose={closeLinkedRunSlideout}
        title="Chi tiết / tiến độ import"
        width={SLIDEOUT_WIDTH}
        data-testid="job-event-linked-import-slideout"
        customFooter={
          <button type="button" className={styles.closeBtn} onClick={closeLinkedRunSlideout}>
            Đóng
          </button>
        }
      >
        <div className={styles.slideoutBody}>
          <JobImportRunDetailPanel
            runDetail={linkedRunDetail}
            loading={loadingLinkedRun}
            showEventsLink={false}
          />
        </div>
      </Slideout>
    </div>
  );
};

export default JobEventsPage;
