import React from 'react';
import { Button } from '../../ui';
import type { ConnectorListRow } from './externalConnectorListUtils';
import styles from './JobInternalPage.module.css';

type Props = {
  rows: ConnectorListRow[];
  loading: boolean;
  searchQuery: string;
  onEdit: (row: ConnectorListRow) => void;
  onSync: (row: ConnectorListRow) => void;
};

export const ExternalConnectorListGrid: React.FC<Props> = ({
  rows,
  loading,
  searchQuery,
  onEdit,
  onSync,
}) => {
  if (loading) {
    return <p className={styles.gridLoading}>Đang tải…</p>;
  }

  if (rows.length === 0) {
    return (
      <div className={styles.gridEmpty} data-testid="connector-list-empty">
        {searchQuery.trim()
          ? 'Không tìm thấy connector phù hợp — thử từ khóa khác.'
          : 'Chưa có connector — restart ERP API rồi bấm Làm mới.'}
      </div>
    );
  }

  return (
    <div className={styles.gridWrap} data-testid="connector-list-grid">
      <table className={styles.gridTable}>
        <thead>
          <tr>
            <th align="left">Connector</th>
            <th align="left">Base URL</th>
            <th align="left">Ngày mặc định</th>
            <th align="left">API key</th>
            <th align="left">Bật</th>
            <th align="right">Thao tác</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r) => (
            <tr key={r.configKey} data-testid={`connector-row-${r.configKey}`}>
              <td>
                <strong>{r.configKey}</strong>
                <div className={styles.gridSub}>{r.searchPath}</div>
              </td>
              <td className={styles.gridMono}>{r.externalBaseUrl ?? '—'}</td>
              <td>{r.defaultRangeLabel}</td>
              <td>{r.hasApiKey ? 'Đã lưu' : '—'}</td>
              <td>{r.isEnabled ? 'Có' : 'Không'}</td>
              <td className={styles.gridActions}>
                <Button
                  type="button"
                  variant="secondary"
                  onClick={() => onEdit(r)}
                  data-testid={`connector-edit-${r.configKey}`}
                >
                  Sửa
                </Button>
                <Button
                  type="button"
                  onClick={() => onSync(r)}
                  disabled={!r.isEnabled}
                  data-testid={`connector-sync-${r.configKey}`}
                >
                  Tạo sync
                </Button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ExternalConnectorListGrid;
